objects.draw:
function(ctx, obj) {
  ctx.save();
  if (obj.angle) {
    const c = Lab.utils.getCenter(obj);
    ctx.translate(c.x, c.y);
    ctx.rotate(obj.angle * Math.PI / 180);
    ctx.translate(-c.x, -c.y);
  }

  ctx.fillStyle = obj.fill;
  ctx.fillRect(obj.x, obj.y, obj.w, obj.h);

  ctx.fillStyle = '#ffffff';
  ctx.font = 'bold 12px monospace';
  ctx.fillText('N', obj.x + 5, obj.y + obj.h/2 + 4);
  ctx.fillText('S', obj.x + obj.w - 15, obj.y + obj.h/2 + 4);

  ctx.restore();
}

objects.update:
function(obj, dt) {
  // Magnetic field influence on charged particles
  for (const other of Lab.state.objects) {
    if (other.charge && other.charge !== 0) {
      const center = Lab.utils.getCenter(obj);
      const otherCenter = Lab.utils.getCenter(other);
      const dx = otherCenter.x - center.x;
      const dy = otherCenter.y - center.y;
      const r = Math.hypot(dx, dy);

      if (r > 5 && r < 200) {
        const B = obj.strength / (r * r);
        const forceX = -other.charge * B * dy;
        const forceY = other.charge * B * dx;

        other.vx += forceX * dt / (other.mass || 1);
        other.vy += forceY * dt / (other.mass || 1);
      }
    }
  }
}

objects.draw:
function(ctx, obj) {
  ctx.fillStyle = obj.fill;
  ctx.fillRect(obj.x, obj.y, obj.w, obj.h);
  ctx.strokeStyle = obj.stroke;
  ctx.lineWidth = 1;
  ctx.strokeRect(obj.x, obj.y, obj.w, obj.h);

  ctx.fillStyle = '#000000';
  ctx.font = '10px monospace';
  ctx.fillText(`${obj.current}A`, obj.x + obj.w/2 - 10, obj.y - 5);
}

objects.update:
function(obj, dt) {
  // Magnetic field from current-carrying wire
  for (const other of Lab.state.objects) {
    if (other.charge && other.charge !== 0 && !other.static) {
      const center = Lab.utils.getCenter(obj);
      const otherCenter = Lab.utils.getCenter(other);
      const dx = otherCenter.x - center.x;
      const dy = otherCenter.y - center.y;
      const r = Math.hypot(dx, dy);

      if (r > 5 && r < 150) {
        const B = (obj.current * 2e-7) / r;
        const forceX = -other.charge * B * dy;
        const forceY = other.charge * B * dx;

        other.vx += forceX * dt / (other.mass || 1);
        other.vy += forceY * dt / (other.mass || 1);
      }
    }
  }
}

simulations.setup:
function() {
  Lab.state.objects.push({
    id: Lab.state.nextId++,
    type: 'circle',
    x: Lab.state.W/2,
    y: Lab.state.H/2,
    w: 15,
    charge: 1,
    mass: 0.5,
    vx: 50,
    vy: 0,
    fill: '#3b82f6',
    stroke: '#1d4ed8'
  });
  Lab.state.magneticField = { x: 0, y: 0, z: 10 };
  Lab.render.all();
}

simulations.update:
function(dt) {
  if (!Lab.state.magneticField) return;

  for (const obj of Lab.state.objects) {
    if (obj.charge && obj.charge !== 0 && !obj.static) {
      const Bz = Lab.state.magneticField.z;
      const fx = obj.charge * obj.vy * Bz;
      const fy = -obj.charge * obj.vx * Bz;

      obj.vx += fx * dt / (obj.mass || 1);
      obj.vy += fy * dt / (obj.mass || 1);
    }
  }
}
